389	}
390	
391	/// Identifies what the user is dragging in the ColorPicker.
392	/// ColorPicker's area targets two channels at once, while channel sliders
393	/// target a single channel.
394	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
395	pub enum DragTarget {
396	    /// 2D area: xChannel=Saturation, yChannel=Lightness (fixed in ColorPicker).
397	    Area,
398	    /// 1D channel slider.
399	    Channel(ColorChannel),
400	}
401	
402	/// Get the current value of a single channel from a ColorValue.
403	pub fn channel_value(color: &ColorValue, channel: ColorChannel) -> f64 {
404	    match channel {
405	        ColorChannel::Hue => color.hue,
406	        ColorChannel::Saturation => color.saturation,
407	        ColorChannel::Lightness => color.lightness,
408	        ColorChannel::Brightness => color.to_hsb().2,
409	        ColorChannel::Alpha => color.alpha,
410	        ColorChannel::Red => color.to_rgb().0 as f64,
411	        ColorChannel::Green => color.to_rgb().1 as f64,
412	        ColorChannel::Blue => color.to_rgb().2 as f64,
413	    }
414	}
415	
416	/// Return a new ColorValue with one channel replaced.
417	pub fn with_channel(color: &ColorValue, channel: ColorChannel, value: f64) -> ColorValue {
418	    match channel {
419	        ColorChannel::Hue => ColorValue::new(value, color.saturation, color.lightness, color.alpha),
420	        ColorChannel::Saturation => ColorValue::new(color.hue, value, color.lightness, color.alpha),
421	        ColorChannel::Lightness => ColorValue::new(color.hue, color.saturation, value, color.alpha),
422	        ColorChannel::Brightness => {
423	            // Convert current HSL to HSB, replace B, convert back
424	            let (h, s_hsb, _) = color.to_hsb();
425	            let v = value.clamp(0.0, 1.0);
426	            let l = v * (1.0 - s_hsb / 2.0);
427	            let s_hsl = if l == 0.0 || l == 1.0 { 0.0 } else { (v - l) / l.min(1.0 - l) };
428	            ColorValue::new(h, s_hsl, l, color.alpha)
429	        }
430	        ColorChannel::Alpha => ColorValue::new(color.hue, color.saturation, color.lightness, value),
431	        ColorChannel::Red => {
432	            let (_, g, b) = color.to_rgb();
433	            let mut c = ColorValue::from_rgb(value.round() as u8, g, b);
434	            c.alpha = color.alpha;
435	            c
436	        }
437	        ColorChannel::Green => {
438	            let (r, _, b) = color.to_rgb();
439	            let mut c = ColorValue::from_rgb(r, value.round() as u8, b);
440	            c.alpha = color.alpha;
441	            c
442	        }
443	        ColorChannel::Blue => {
444	            let (r, g, _) = color.to_rgb();
445	            let mut c = ColorValue::from_rgb(r, g, value.round() as u8);
446	            c.alpha = color.alpha;
447	            c
448	        }
449	    }
450	}
