452	/// (min, max) range for a channel.
453	pub fn channel_range(channel: ColorChannel) -> (f64, f64) {
454	    match channel {
455	        ColorChannel::Hue => (0.0, 360.0),
456	        ColorChannel::Red | ColorChannel::Green | ColorChannel::Blue => (0.0, 255.0),
457	        _ => (0.0, 1.0), // Saturation, Lightness, Brightness, Alpha
458	    }
459	}
460	
461	/// Default step size for keyboard adjustment.
462	pub fn channel_step_default(channel: ColorChannel) -> f64 {
463	    match channel {
464	        ColorChannel::Hue => 1.0,        // 1 degree
465	        ColorChannel::Red | ColorChannel::Green | ColorChannel::Blue => 1.0,
466	        _ => 0.01,                        // 1% for 0..1 range channels
467	    }
468	}
