470	/// Strip a functional notation call: `name(...)` -> inner content.
471	fn strip_fn_call<'a>(input: &'a str, name: &str) -> Option<&'a str> {
472	    let stripped = input.strip_prefix(name)?;
473	    let stripped = stripped.strip_prefix('(')?.strip_suffix(')')?;
474	
475	    Some(stripped)
476	}
477	
478	/// Parse "r, g, b" or "r, g, b, a" inside rgb()/rgba().
479	fn parse_rgb_args(inner: &str, has_alpha: bool) -> Option<ColorValue> {
480	    let parts: Vec<&str> = inner.split(',').map(str::trim).collect();
481	    if has_alpha && parts.len() != 4 { return None; }
482	    if !has_alpha && parts.len() != 3 { return None; }
483	    let r: u8 = parts[0].parse().ok()?;
484	    let g: u8 = parts[1].parse().ok()?;
485	    let b: u8 = parts[2].parse().ok()?;
486	    let a: f64 = if has_alpha { parts[3].parse().ok()? } else { 1.0 };
487	
488	    ColorValue::from_rgb(r, g, b).map(|mut c| { c.alpha = a.clamp(0.0, 1.0); c })
489	}
490	
491	/// Parse "h, s%, l%" or "h, s%, l%, a" inside hsl()/hsla().
492	fn parse_hsl_args(inner: &str, has_alpha: bool) -> Option<ColorValue> {
493	    let parts: Vec<&str> = inner.split(',').map(str::trim).collect();
494	    if has_alpha && parts.len() != 4 { return None; }
495	    if !has_alpha && parts.len() != 3 { return None; }
496	    let h: f64 = parts[0].parse().ok()?;
497	    let s: f64 = parts[1].strip_suffix('%')?.trim().parse::<f64>().ok()? / 100.0;
498	    let l: f64 = parts[2].strip_suffix('%')?.trim().parse::<f64>().ok()? / 100.0;
499	    let a: f64 = if has_alpha { parts[3].parse().ok()? } else { 1.0 };
500	
501	    Some(ColorValue::new(h, s, l, a.clamp(0.0, 1.0)))
502	}
503	
504	/// Parse "h, s%, b%" inside hsb() or "h, s%, b%, a" inside hsba().
505	fn parse_hsb_args(inner: &str, has_alpha: bool) -> Option<ColorValue> {
506	    let parts: Vec<&str> = inner.split(',').map(str::trim).collect();
507	    let expected = if has_alpha { 4 } else { 3 };
508	    if parts.len() != expected { return None; }
509	    let h: f64 = parts[0].parse().ok()?;
510	    // Clamp the HSB channels to `0..=1` before the conversion so out-of-range
511	    // input (e.g. `200%`) doesn't skew lightness/saturation and lose the hue.
512	    let s: f64 = (parts[1].strip_suffix('%')?.trim().parse::<f64>().ok()? / 100.0).clamp(0.0, 1.0);
513	    let b: f64 = (parts[2].strip_suffix('%')?.trim().parse::<f64>().ok()? / 100.0).clamp(0.0, 1.0);
514	    let a: f64 = if has_alpha { parts[3].parse().ok()? } else { 1.0 };
515	    // Convert HSB -> HSL: lightness = b * (1 - s/2)
516	    let l = b * (1.0 - s / 2.0);
517	    let sl = if l > 0.0 && l < 1.0 { (b - l) / l.min(1.0 - l) } else { 0.0 };
518	
519	    Some(ColorValue::new(h, sl, l, a.clamp(0.0, 1.0)))
520	}
521	
522	/// Parse a user-typed string into a ColorValue.
523	/// Recognizes: "#rrggbb", "#rrggbbaa", "rgb(r,g,b)", "rgba(r,g,b,a)",
524	/// "hsl(h,s%,l%)", "hsla(h,s%,l%,a)", "hsb(h,s%,b%)".
525	pub fn parse_color_string(input: &str) -> Option<ColorValue> {
526	    let trimmed = input.trim();
527	    if trimmed.starts_with('#') {
528	        return ColorValue::from_hex(trimmed);
529	    }
530	    if let Some(inner) = strip_fn_call(trimmed, "rgba") {
531	        return parse_rgb_args(inner, true);
532	    }
533	    if let Some(inner) = strip_fn_call(trimmed, "rgb") {
534	        return parse_rgb_args(inner, false);
535	    }
536	    if let Some(inner) = strip_fn_call(trimmed, "hsla") {
537	        return parse_hsl_args(inner, true);
538	    }
539	    if let Some(inner) = strip_fn_call(trimmed, "hsl") {
540	        return parse_hsl_args(inner, false);
541	    }
542	    if let Some(inner) = strip_fn_call(trimmed, "hsba") {
543	        return parse_hsb_args(inner, true);
544	    }
545	    if let Some(inner) = strip_fn_call(trimmed, "hsb") {
546	        return parse_hsb_args(inner, false);
547	    }
548	
549	    None
550	}
