552	/// Format a ColorValue as a string in the given format.
553	pub fn format_color_string(color: &ColorValue, format: ColorFormat) -> String {
554	    match format {
555	        ColorFormat::Hex => color.to_hex(color.alpha < 1.0),
556	        ColorFormat::Rgb => {
557	            let (r, g, b) = color.to_rgb();
558	            if color.alpha < 1.0 {
559	                format!("rgba({}, {}, {}, {:.2})", r, g, b, color.alpha)
560	            } else {
561	                format!("rgb({}, {}, {})", r, g, b)
562	            }
563	        }
564	        ColorFormat::Hsl => color.to_css_hsl(),
565	        ColorFormat::Hsb => {
566	            let (h, s, b) = color.to_hsb();
567	            // Emit `hsba(...)` for translucent colors so alpha round-trips
568	            // through the parser instead of being silently dropped to opaque.
569	            if color.alpha < 1.0 {
570	                format!("hsba({:.0}, {:.1}%, {:.1}%, {:.2})", h, s * 100.0, b * 100.0, color.alpha)
571	            } else {
572	                format!("hsb({:.0}, {:.1}%, {:.1}%)", h, s * 100.0, b * 100.0)
573	            }
574	        }
575	    }
576	}
