1	//! `ColorArea` component state machine and connect API.
2	//!
3	//! `ColorArea` is a 2D color picker: the thumb position maps to two color
4	//! channels (x and y). It owns the channel math, value state, keyboard
5	//! behavior, and ARIA/data attributes. Live area measurement, pointer capture,
6	//! and coordinate-to-value conversion are adapter concerns: the adapter
7	//! supplies already-normalized `(x, y)` in `0..=1` via [`Api::on_background_pointer_down`]
8	//! (drag start) and drives [`Event::DragMove`] / [`Event::DragEnd`] from its own
9	//! pointer listeners, exactly as the slider does.
10	
11	use alloc::{format, string::String, vec::Vec};
12	use core::fmt::{self, Debug};
13	
14	use ars_core::{
15	    AriaAttr, AttrMap, Bindable, Callback, ColorChannel, ColorValue, ComponentIds,
16	    ComponentMessages, ComponentPart, ConnectApi, CssProperty, Direction, Env, HtmlAttr,
17	    KeyboardKey, Locale, MessageFn, PendingEffect, TransitionPlan, channel_range, channel_value,
18	    no_cleanup, with_channel,
19	};
20	use ars_interactions::KeyboardEventData;
21	
22	/// Label for the area thumb.
23	type LabelFn = dyn Fn(&Locale) -> String + Send + Sync;
24	
25	/// Role description for the area thumb.
26	type RoleDescriptionFn = dyn Fn(&Locale) -> String + Send + Sync;
27	
28	/// Formats the `aria-valuetext`. Arguments: `x_axis_reading` (channel-aware,
29	/// e.g. `"saturation 80%"` or `"hue 180°"`), `y_axis_reading`, `color_name`,
30	/// `locale`. Readings are preformatted per channel so non-fractional channels
31	/// (hue/RGB) are not mis-rendered as percentages.
32	type ValueTextFn = dyn Fn(&str, &str, &str, &Locale) -> String + Send + Sync;
33	
34	/// Consumer callback fired on drag-end / pointer release.
35	type ChangeEndFn = dyn Fn(ColorValue) + Send + Sync;
36	
37	/// The states for the `ColorArea` component.
38	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
39	pub enum State {
40	    /// No interaction in progress.
41	    Idle,
42	
43	    /// The user is dragging the thumb.
44	    Dragging,
45	}
