139	    /// normalizes hue into `[0, 360)`, so reading a hue axis back from the color
140	    /// would collapse the 360° endpoint onto 0°; tracking it here keeps the
141	    /// endpoint distinct. See [`Context::y_value`](Self::y_value).
142	    pub x_value: f64,
