244	/// The messages for the `ColorArea` component.
245	#[derive(Clone, Debug, PartialEq)]
246	pub struct Messages {
247	    /// Label for the area thumb. Default: `"Color area"`.
248	    pub label: MessageFn<LabelFn>,
249	
250	    /// Role description for screen readers. Default: `"2d color picker"`.
251	    pub role_description: MessageFn<RoleDescriptionFn>,
252	
