259	        Self {
260	            label: MessageFn::static_str("Color area"),
261	            role_description: MessageFn::static_str("2d color picker"),
262	            value_text: MessageFn::new(
263	                |x_reading: &str, y_reading: &str, color_name: &str, _locale: &Locale| {
264	                    format!("{color_name}, {x_reading}, {y_reading}")
265	                },
