273	/// Format a single channel reading for `aria-valuetext`, including the channel
274	/// name and a channel-appropriate unit (degrees for hue, raw for the 8-bit RGB
275	/// channels, a percentage for the fractional channels).
276	fn format_axis_reading(channel: ColorChannel, value: f64) -> String {
277	    let name = format!("{channel:?}").to_lowercase();
278	
279	    match channel {
280	        ColorChannel::Hue => format!("{name} {value:.0}°"),
281	        ColorChannel::Red | ColorChannel::Green | ColorChannel::Blue => {
282	            format!("{name} {value:.0}")
283	        }
284	        _ => format!("{name} {:.0}%", value * 100.0),
285	    }
286	}
287	
288	/// Apply normalized `(x, y)` coordinates to both channels (y is inverted: top = max).
289	fn apply_area_position(ctx: &mut Context, x: f64, y: f64) {
290	    let (x_min, x_max) = channel_range(ctx.x_channel);
291	    let (y_min, y_max) = channel_range(ctx.y_channel);
292	
293	    // RTL renders the minimum x on the right and mirrors the x-axis arrows, so
294	    // the incoming physical x is inverted to match (left edge selects max).
295	    let x_norm = x.clamp(0.0, 1.0);
296	    let x_norm = if ctx.dir == Direction::Rtl {
297	        1.0 - x_norm
298	    } else {
299	        x_norm
300	    };
301	
302	    let x_val = x_min + x_norm * (x_max - x_min);
303	    let y_val = y_max - y.clamp(0.0, 1.0) * (y_max - y_min);
304	
305	    ctx.x_value = x_val;
306	    ctx.y_value = y_val;
307	
308	    // Apply both channels from the pending color in a single read. Reading
309	    // `get()` in controlled mode returns the stale prop, and reading the bindable
310	    // twice (as two `set_*_value` calls) would discard the first change.
311	    let color = *ctx.value.pending();
312	    let updated = with_channel(&color, ctx.x_channel, x_val);
313	    ctx.value.set(with_channel(&updated, ctx.y_channel, y_val));
314	}
315	
316	/// Set the x-axis channel value (unwrapped) and derive the color from it.
317	///
318	/// Bases the new color on the *pending* value so a prior single-axis change
319	/// (e.g. an earlier `IncrementY`) is preserved in controlled mode, where
320	/// `get()` still returns the unchanged controlled prop.
321	fn set_x_value(ctx: &mut Context, value: f64) {
322	    ctx.x_value = value;
323	
324	    let color = *ctx.value.pending();
325	    ctx.value.set(with_channel(&color, ctx.x_channel, value));
326	}
327	
328	/// Set the y-axis channel value (unwrapped) and derive the color from it.
329	///
330	/// Bases the new color on the *pending* value (see [`set_x_value`]).
331	fn set_y_value(ctx: &mut Context, value: f64) {
332	    ctx.y_value = value;
333	
334	    let color = *ctx.value.pending();
335	    ctx.value.set(with_channel(&color, ctx.y_channel, value));
336	}
337	
338	/// Build the change-end effect that invokes `Props::on_change_end`.
339	///
340	/// Reports the *pending* value staged during the drag rather than the
341	/// controlled `get()` value, which in controlled mode still holds the stale
342	/// pre-drag color until the parent syncs the new value back through its prop.
343	fn change_end_effect() -> PendingEffect<Machine> {
344	    PendingEffect::new(Effect::ChangeEnd, |ctx: &Context, props: &Props, _send| {
345	        if let Some(callback) = &props.on_change_end {
346	            callback(*ctx.value.pending());
347	        }
348	
349	        no_cleanup()
350	    })
351	}
