353	/// The machine for the `ColorArea` component.
354	#[derive(Debug)]
355	pub struct Machine;
356	
357	impl ars_core::Machine for Machine {
358	    type State = State;
359	    type Event = Event;
360	    type Context = Context;
361	    type Props = Props;
362	    type Messages = Messages;
363	    type Effect = Effect;
364	    type Api<'a> = Api<'a>;
365	
366	    fn init(
367	        props: &Self::Props,
368	        env: &Env,
369	        messages: &Self::Messages,
370	    ) -> (Self::State, Self::Context) {
371	        let value = if let Some(v) = &props.value {
372	            Bindable::controlled(*v)
373	        } else {
374	            Bindable::uncontrolled(props.default_value)
375	        };
376	
377	        let x_value = channel_value(value.get(), props.x_channel);
378	        let y_value = channel_value(value.get(), props.y_channel);
379	
380	        let context = Context {
381	            value,
382	            x_value,
383	            y_value,
384	            x_channel: props.x_channel,
385	            y_channel: props.y_channel,
386	            disabled: props.disabled,
387	            readonly: props.readonly,
388	            focused: false,
389	            focus_visible: false,
390	            step: props.step,
391	            large_step: props.large_step,
392	            dir: props.dir,
393	            locale: env.locale.clone(),
394	            messages: messages.clone(),
395	            ids: ComponentIds::from_id(&props.id),
396	        };
397	
398	        (State::Idle, context)
399	    }
400	
401	    fn transition(
402	        state: &Self::State,
403	        event: &Self::Event,
404	        ctx: &Self::Context,
405	        props: &Self::Props,
406	    ) -> Option<TransitionPlan<Self>> {
407	        // A disabled area ignores value-changing input but still tracks focus
408	        // and accepts parent-driven prop syncs (so it can be re-enabled).
409	        // `DragEnd` is allowed through so a drag in flight when the parent
410	        // disabled the control can still terminate cleanly.
411	        if ctx.disabled {
412	            match event {
413	                Event::DragStart { .. }
414	                | Event::DragMove { .. }
415	                | Event::IncrementX { .. }
416	                | Event::DecrementX { .. }
417	                | Event::IncrementY { .. }
418	                | Event::DecrementY { .. }
419	                | Event::SetXToMin
420	                | Event::SetXToMax
421	                | Event::SetYToMin
422	                | Event::SetYToMax => return None,
423	                _ => {}
424	            }
425	        }
426	
427	        match (state, event) {
428	            (State::Idle, Event::DragStart { x, y }) => {
429	                if ctx.readonly {
430	                    return None;
431	                }
432	
433	                let (x, y) = (*x, *y);
434	                Some(
435	                    TransitionPlan::to(State::Dragging).apply(move |ctx: &mut Context| {
436	                        apply_area_position(ctx, x, y);
437	                    }),
438	                )
439	            }
440	
441	            (State::Dragging, Event::DragMove { x, y }) => {
442	                // Readonly toggled mid-drag must stop further value changes
443	                // (disabled is already handled by the guard above); DragEnd
444	                // still terminates the drag.
445	                if ctx.readonly {
446	                    return None;
447	                }
448	
449	                let (x, y) = (*x, *y);
450	                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
451	                    apply_area_position(ctx, x, y);
452	                }))
453	            }
454	
455	            (State::Dragging, Event::DragEnd) => {
456	                Some(TransitionPlan::to(State::Idle).with_effect(change_end_effect()))
457	            }
458	
459	            (_, Event::IncrementX { step }) => {
460	                if ctx.readonly {
461	                    return None;
462	                }
463	
464	                let step = *step;
465	                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
466	                    let (_, max) = channel_range(ctx.x_channel);
467	                    set_x_value(ctx, (ctx.x_value + step).min(max));
468	                }))
469	            }
470	
471	            (_, Event::DecrementX { step }) => {
472	                if ctx.readonly {
473	                    return None;
474	                }
475	
476	                let step = *step;
477	                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
478	                    let (min, _) = channel_range(ctx.x_channel);
479	                    set_x_value(ctx, (ctx.x_value - step).max(min));
480	                }))
481	            }
482	
483	            (_, Event::IncrementY { step }) => {
484	                if ctx.readonly {
485	                    return None;
486	                }
487	
488	                let step = *step;
489	                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
490	                    let (_, max) = channel_range(ctx.y_channel);
491	                    set_y_value(ctx, (ctx.y_value + step).min(max));
492	                }))
493	            }
494	
495	            (_, Event::DecrementY { step }) => {
496	                if ctx.readonly {
497	                    return None;
498	                }
499	
500	                let step = *step;
501	                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
502	                    let (min, _) = channel_range(ctx.y_channel);
503	                    set_y_value(ctx, (ctx.y_value - step).max(min));
504	                }))
505	            }
506	
507	            (_, Event::SetXToMin) => {
508	                if ctx.readonly {
509	                    return None;
510	                }
511	
512	                Some(TransitionPlan::context_only(|ctx: &mut Context| {
513	                    let (min, _) = channel_range(ctx.x_channel);
514	                    set_x_value(ctx, min);
515	                }))
516	            }
517	
518	            (_, Event::SetXToMax) => {
519	                if ctx.readonly {
520	                    return None;
521	                }
522	
523	                Some(TransitionPlan::context_only(|ctx: &mut Context| {
524	                    let (_, max) = channel_range(ctx.x_channel);
525	                    set_x_value(ctx, max);
526	                }))
527	            }
528	
529	            (_, Event::SetYToMin) => {
530	                if ctx.readonly {
531	                    return None;
532	                }
533	
534	                Some(TransitionPlan::context_only(|ctx: &mut Context| {
535	                    let (min, _) = channel_range(ctx.y_channel);
536	                    set_y_value(ctx, min);
537	                }))
538	            }
539	
540	            (_, Event::SetYToMax) => {
541	                if ctx.readonly {
542	                    return None;
543	                }
544	
545	                Some(TransitionPlan::context_only(|ctx: &mut Context| {
546	                    let (_, max) = channel_range(ctx.y_channel);
547	                    set_y_value(ctx, max);
548	                }))
549	            }
550	
551	            (_, Event::Focus { is_keyboard }) => {
552	                let kb = *is_keyboard;
553	                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
554	                    ctx.focused = true;
555	                    ctx.focus_visible = kb;
556	                }))
557	            }
558	
559	            (_, Event::Blur) => Some(TransitionPlan::context_only(|ctx: &mut Context| {
560	                ctx.focused = false;
561	                ctx.focus_visible = false;
562	            })),
563	
564	            (_, Event::SyncValue(value)) => {
565	                let value = *value;
566	                Some(TransitionPlan::context_only(
567	                    move |ctx: &mut Context| match value {
568	                        Some(color) => {
569	                            // Keep the cached axis values when the parent echoes the
570	                            // value we emitted, so a hue 360° endpoint isn't
571	                            // re-derived back to 0° (the color normalizes 360°->0°).
572	                            let echoes_pending = color == *ctx.value.pending();
573	
574	                            ctx.value.set(color);
575	                            ctx.value.sync_controlled(Some(color));
576	
577	                            if !echoes_pending {
578	                                ctx.x_value = channel_value(&color, ctx.x_channel);
579	                                ctx.y_value = channel_value(&color, ctx.y_channel);
580	                            }
581	                        }
582	                        None => ctx.value.sync_controlled(None),
583	                    },
584	                ))
585	            }
586	
587	            (_, Event::SetProps) => {
588	                let props = props.clone();
589	                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
590	                    let x_channel_changed = ctx.x_channel != props.x_channel;
591	                    let y_channel_changed = ctx.y_channel != props.y_channel;
592	
593	                    ctx.x_channel = props.x_channel;
594	                    ctx.y_channel = props.y_channel;
595	                    ctx.step = props.step;
596	                    ctx.large_step = props.large_step;
597	                    ctx.disabled = props.disabled;
598	                    ctx.readonly = props.readonly;
599	                    ctx.dir = props.dir;
600	
601	                    // A new axis channel means the cached axis value refers to the
602	                    // old channel; re-derive it from the current color.
603	                    if x_channel_changed {
604	                        ctx.x_value = channel_value(ctx.value.get(), ctx.x_channel);
605	                    }
606	                    if y_channel_changed {
607	                        ctx.y_value = channel_value(ctx.value.get(), ctx.y_channel);
608	                    }
609	                }))
610	            }
611	
612	            _ => None,
613	        }
614	    }
615	
616	    fn on_props_changed(old: &Props, new: &Props) -> Vec<Event> {
617	        assert_eq!(
618	            old.id, new.id,
619	            "color_area::Props.id must remain stable after init"
620	        );
621	
622	        let mut events = Vec::new();
623	
624	        if old.value != new.value {
625	            events.push(Event::SyncValue(new.value));
626	        }
627	
628	        if props_output_changed(old, new) {
629	            events.push(Event::SetProps);
630	        }
631	
632	        events
633	    }
634	
635	    fn connect<'a>(
636	        state: &'a Self::State,
637	        ctx: &'a Self::Context,
638	        props: &'a Self::Props,
639	        send: &'a dyn Fn(Self::Event),
640	    ) -> Self::Api<'a> {
641	        Api {
642	            state,
643	            ctx,
644	            props,
645	            send,
646	        }
647	    }
648	}
