711	    /// Attributes for the root element.
712	    #[must_use]
713	    pub fn root_attrs(&self) -> AttrMap {
714	        let mut attrs = AttrMap::new();
715	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Root.data_attrs();
716	
717	        attrs
718	            .set(scope_attr, scope_val)
719	            .set(part_attr, part_val)
720	            .set(HtmlAttr::Role, "group");
721	
722	        if self.ctx.disabled {
723	            attrs.set_bool(HtmlAttr::Data("ars-disabled"), true);
724	        }
725	
726	        if self.ctx.readonly {
727	            attrs.set_bool(HtmlAttr::Data("ars-readonly"), true);
728	        }
729	
730	        if self.is_dragging() {
731	            attrs.set_bool(HtmlAttr::Data("ars-dragging"), true);
732	        }
733	
734	        attrs
735	    }
