737	    /// Attributes for the gradient background element.
738	    #[must_use]
739	    pub fn background_attrs(&self) -> AttrMap {
740	        let mut attrs = AttrMap::new();
741	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Background.data_attrs();
742	
743	        attrs.set(scope_attr, scope_val).set(part_attr, part_val);
744	
745	        // Pending color so the background tracks an in-progress controlled drag.
746	        let color = self.ctx.value.pending();
747	
748	        // Dominant hue backdrop (kept for the default saturation×lightness case).
749	        attrs.set_style(
750	            CssProperty::Custom("ars-color-area-bg"),
751	            format!("hsl({:.0}, 100%, 50%)", color.hue),
752	        );
753	
754	        // Expose the configured axes plus the four corner colors so the adapter
755	        // can render a 2D gradient that matches *any* x/y channel pair, not just
756	        // the default surface. Corners are emitted in visual order (top = the
757	        // y-axis maximum since y is inverted; left/right follow the RTL x flip).
758	        let (x_min, x_max) = channel_range(self.ctx.x_channel);
759	        let (y_min, y_max) = channel_range(self.ctx.y_channel);
760	
761	        let (left_x, right_x) = if self.ctx.dir == Direction::Rtl {
762	            (x_max, x_min)
763	        } else {
764	            (x_min, x_max)
765	        };
766	
767	        let corner = |x_value: f64, y_value: f64| {
768	            let with_x = with_channel(color, self.ctx.x_channel, x_value);
769	            with_channel(&with_x, self.ctx.y_channel, y_value).to_css_hsl()
770	        };
771	
772	        attrs
773	            .set(
774	                HtmlAttr::Data("ars-x-channel"),
775	                format!("{:?}", self.ctx.x_channel).to_lowercase(),
776	            )
777	            .set(
778	                HtmlAttr::Data("ars-y-channel"),
779	                format!("{:?}", self.ctx.y_channel).to_lowercase(),
780	            )
781	            .set_style(
782	                CssProperty::Custom("ars-color-area-corner-tl"),
783	                corner(left_x, y_max),
784	            )
785	            .set_style(
786	                CssProperty::Custom("ars-color-area-corner-tr"),
787	                corner(right_x, y_max),
788	            )
789	            .set_style(
790	                CssProperty::Custom("ars-color-area-corner-bl"),
791	                corner(left_x, y_min),
792	            )
793	            .set_style(
794	                CssProperty::Custom("ars-color-area-corner-br"),
795	                corner(right_x, y_min),
796	            );
797	
798	        attrs
799	    }
800	
801	    /// Attributes for the draggable thumb element.
802	    #[must_use]
803	    pub fn thumb_attrs(&self) -> AttrMap {
804	        let mut attrs = AttrMap::new();
805	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Thumb.data_attrs();
806	
807	        attrs
808	            .set(scope_attr, scope_val)
809	            .set(part_attr, part_val)
810	            .set(HtmlAttr::Id, self.ctx.ids.part("thumb"))
811	            .set(HtmlAttr::Role, "application")
812	            .set(
813	                HtmlAttr::Aria(AriaAttr::RoleDescription),
814	                (self.ctx.messages.role_description)(&self.ctx.locale),
815	            )
816	            // A disabled control must stay out of the tab order.
817	            .set(
818	                HtmlAttr::TabIndex,
819	                if self.ctx.disabled { "-1" } else { "0" },
820	            )
821	            .set(
822	                HtmlAttr::Aria(AriaAttr::Label),
823	                (self.ctx.messages.label)(&self.ctx.locale),
824	            );
825	
826	        if self.ctx.disabled {
827	            attrs.set(HtmlAttr::Aria(AriaAttr::Disabled), "true");
828	        }
829	
830	        // Pending color so the thumb background and color name match the
831	        // in-progress drag in controlled mode.
832	        let color = self.ctx.value.pending();
833	
834	        // Unwrapped axis values keep hue endpoints (360°) distinct from 0°.
835	        let x_val = self.ctx.x_value;
836	        let y_val = self.ctx.y_value;
837	
838	        let (x_min, x_max) = channel_range(self.ctx.x_channel);
839	        let (y_min, y_max) = channel_range(self.ctx.y_channel);
840	
841	        let x_reading = format_axis_reading(self.ctx.x_channel, x_val);
842	        let y_reading = format_axis_reading(self.ctx.y_channel, y_val);
843	        let color_name = color.color_name_en();
844	
845	        attrs.set(
846	            HtmlAttr::Aria(AriaAttr::ValueText),
847	            (self.ctx.messages.value_text)(&x_reading, &y_reading, &color_name, &self.ctx.locale),
848	        );
849	
850	        let mut x_pct = if (x_max - x_min).abs() > f64::EPSILON {
851	            (x_val - x_min) / (x_max - x_min) * 100.0
852	        } else {
853	            0.0
854	        };
855	
856	        // RTL flips the x gradient horizontally (min on the right), matching the
857	        // mirrored x-axis arrow handling in `on_thumb_keydown`.
858	        if self.ctx.dir == Direction::Rtl {
859	            x_pct = 100.0 - x_pct;
860	        }
861	
862	        let y_pct = if (y_max - y_min).abs() > f64::EPSILON {
863	            (1.0 - (y_val - y_min) / (y_max - y_min)) * 100.0
864	        } else {
865	            0.0
866	        };
867	
868	        attrs
869	            .set_style(
870	                CssProperty::Custom("ars-color-area-thumb-x"),
871	                format!("{x_pct:.1}%"),
872	            )
873	            .set_style(
874	                CssProperty::Custom("ars-color-area-thumb-y"),
875	                format!("{y_pct:.1}%"),
876	            )
877	            .set_style(CssProperty::BackgroundColor, color.to_css_hsl())
878	            .set(
879	                HtmlAttr::Aria(AriaAttr::KeyShortcuts),
880	                "ArrowUp ArrowDown ArrowLeft ArrowRight",
881	            );
882	
883	        if self.is_dragging() {
884	            attrs.set_bool(HtmlAttr::Data("ars-dragging"), true);
885	        }
886	
887	        if self.ctx.focus_visible {
888	            attrs.set_bool(HtmlAttr::Data("ars-focus-visible"), true);
889	        }
890	
891	        attrs
892	    }
