894	    /// Attributes for the hidden form input.
895	    #[must_use]
896	    pub fn hidden_input_attrs(&self) -> AttrMap {
897	        let mut attrs = AttrMap::new();
898	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::HiddenInput.data_attrs();
899	
900	        attrs
901	            .set(scope_attr, scope_val)
902	            .set(part_attr, part_val)
903	            .set(HtmlAttr::Type, "hidden");
904	
905	        if let Some(name) = &self.props.name {
906	            attrs.set(HtmlAttr::Name, name.clone());
907	        }
908	
909	        attrs.set(HtmlAttr::Value, self.ctx.value.pending().to_hex(true));
910	
911	        // A disabled control must be omitted from form submission.
912	        if self.ctx.disabled {
913	            attrs.set_bool(HtmlAttr::Disabled, true);
914	        }
