919	    /// Handles a keydown on the thumb. `shift` selects the large step.
920	    ///
921	    /// In RTL, the x-axis arrow keys are mirrored so `ArrowLeft` increments and
922	    /// `ArrowRight` decrements; the y-axis and Home/End/PageUp/PageDown are
923	    /// direction-independent.
924	    pub fn on_thumb_keydown(&self, data: &KeyboardEventData, shift: bool) {
925	        let step = if shift {
926	            self.ctx.large_step
927	        } else {
928	            self.ctx.step
929	        };
930	
931	        let rtl = self.ctx.dir == Direction::Rtl;
932	
933	        match data.key {
934	            KeyboardKey::ArrowRight => (self.send)(if rtl {
935	                Event::DecrementX { step }
936	            } else {
937	                Event::IncrementX { step }
938	            }),
939	
940	            KeyboardKey::ArrowLeft => (self.send)(if rtl {
941	                Event::IncrementX { step }
942	            } else {
943	                Event::DecrementX { step }
944	            }),
945	
946	            KeyboardKey::ArrowUp => (self.send)(Event::IncrementY { step }),
947	
948	            KeyboardKey::ArrowDown => (self.send)(Event::DecrementY { step }),
949	
950	            KeyboardKey::Home => (self.send)(Event::SetXToMin),
951	
952	            KeyboardKey::End => (self.send)(Event::SetXToMax),
953	
954	            KeyboardKey::PageUp => (self.send)(Event::SetYToMax),
955	
956	            KeyboardKey::PageDown => (self.send)(Event::SetYToMin),
957	
958	            _ => {}
959	        }
960	    }
961	
962	    /// Dispatches a drag-start from an adapter-resolved normalized `(x, y)`.
963	    pub fn on_background_pointer_down(&self, x: f64, y: f64) {
964	        (self.send)(Event::DragStart { x, y });
965	    }
966	}
