18	
19	    fn arb_event() -> impl Strategy<Value = Event> {
20	        prop_oneof![
21	            (0.0f64..1.0, 0.0f64..1.0).prop_map(|(x, y)| Event::DragStart { x, y }),
22	            (0.0f64..1.0, 0.0f64..1.0).prop_map(|(x, y)| Event::DragMove { x, y }),
23	            Just(Event::DragEnd),
24	            (0.0f64..0.5).prop_map(|step| Event::IncrementX { step }),
25	            (0.0f64..0.5).prop_map(|step| Event::DecrementX { step }),
26	            (0.0f64..0.5).prop_map(|step| Event::IncrementY { step }),
27	            (0.0f64..0.5).prop_map(|step| Event::DecrementY { step }),
28	            Just(Event::SetXToMin),
29	            Just(Event::SetXToMax),
30	            Just(Event::SetYToMin),
31	            Just(Event::SetYToMax),
32	            any::<bool>().prop_map(|is_keyboard| Event::Focus { is_keyboard }),
33	            Just(Event::Blur),
34	        ]
35	    }
36	
37	    proptest! {
38	        #![proptest_config(super::super::common::proptest_config())]
39	
40	        #[test]
41	        #[ignore = "proptest — nightly extended-proptest job"]
42	        fn area_event_sequences_keep_value_valid(
43	            events in prop::collection::vec(arb_event(), 0..64),
44	        ) {
45	            let mut svc = Service::<Machine>::new(
46	                Props { id: "ca".into(), ..Props::default() },
47	                &Env::default(),
48	                &Default::default(),
49	            );
50	
51	            for ev in events {
52	                drop(svc.send(ev));
53	            }
54	
55	            let api = svc.connect(&|_| {});
56	
57	            let value = *api.value();
58	
59	            prop_assert!((0.0..360.0).contains(&value.hue));
60	            prop_assert!((0.0..=1.0).contains(&value.saturation));
61	            prop_assert!((0.0..=1.0).contains(&value.lightness));
62	
63	            // connect output reflects the in-range state: the thumb always
64	            // exposes a non-empty `aria-valuetext` describing the current color.
